import React, { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import TaskCard from '../components/TaskCard';
import AddTaskModal from '../components/AddTaskModal';
import Login from './Login';
import Signup from './Signup';
import { motion, AnimatePresence } from 'framer-motion'; // Yeh missing tha
import { LayoutDashboard, Clock, AlertCircle, Plus } from 'lucide-react';
import axios from 'axios';

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [authMode, setAuthMode] = useState(null); // 'login' or 'signup'

  const token = localStorage.getItem('token');
  const name = localStorage.getItem('name') || 'Chief';
  const role = localStorage.getItem('role') || 'member';

  const fetchTasks = async () => {
    if (!token) return; // Token nahi hai toh fetch mat karo
    try {
      const res = await axios.get('http://localhost:5000/api/tasks', {
        headers: { 'x-auth-token': token }
      });
      setTasks(res.data);
    } catch (err) { 
      console.log("Fetch error:", err); 
    }
  };

  useEffect(() => { 
    fetchTasks(); 
  }, [token]);

  // Auth close hone ke baad refresh aur modal close handle karega
  const handleAuthSuccess = () => {
    setAuthMode(null);
    window.location.reload(); // Pura state refresh karne ke liye best hai
  };

  const overdue = tasks.filter(t => t.dueDate && new Date(t.dueDate) < new Date() && t.status !== 'Completed').length;

  return (
    <div className="min-h-screen bg-[#020617] text-white">
      {/* Navbar ko trigger functions pass kiye */}
      <Navbar onLoginClick={() => setAuthMode('login')} onSignupClick={() => setAuthMode('signup')} />

      {/* Auth Modal Overlay - Isko handleAuthSuccess pass kiya hai */}
      <AnimatePresence>
        {authMode && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/90 backdrop-blur-sm p-4">
            <div className="relative w-full max-w-sm">
              <button 
                onClick={() => setAuthMode(null)} 
                className="absolute -top-12 right-0 text-white hover:text-red-400 font-bold transition-all"
              >
                ✕ CLOSE
              </button>
              
              {authMode === 'login' ? (
                <Login onSuccess={handleAuthSuccess} />
              ) : (
                <Signup onSuccess={handleAuthSuccess} />
              )}
            </div>
          </div>
        )}
      </AnimatePresence>

      <AddTaskModal isOpen={isTaskModalOpen} onClose={() => setIsTaskModalOpen(false)} refreshTasks={fetchTasks} />

      <main className="pt-32 pb-20 px-6 max-w-7xl mx-auto">
        <header className="mb-12">
          <h1 className="text-5xl font-black italic tracking-tighter">HI, {name.toUpperCase()} 👋</h1>
          <p className="text-gray-500 mt-2 text-lg">System Status: <span className="text-indigo-500 font-bold uppercase">{role} ACCESS</span></p>
        </header>

        {/* Bento Stats */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-16">
          <div className="p-8 bg-white/5 border border-white/10 rounded-[2rem] hover:bg-white/10 transition-all group">
            <LayoutDashboard className="text-blue-400 mb-4 group-hover:scale-110 transition-transform" />
            <div className="text-4xl font-black">{token ? tasks.length : '0'}</div>
            <div className="text-gray-500 text-xs font-bold uppercase tracking-widest mt-1">Total Assignments</div>
          </div>
          <div className="p-8 bg-white/5 border border-white/10 rounded-[2rem] hover:bg-white/10 transition-all group">
            <AlertCircle className="text-red-500 mb-4 group-hover:scale-110 transition-transform" />
            <div className="text-4xl font-black">{token ? overdue : '0'}</div>
            <div className="text-gray-500 text-xs font-bold uppercase tracking-widest mt-1">Overdue Critical</div>
          </div>
          <div className="p-8 bg-white/5 border border-white/10 rounded-[2rem] hover:bg-white/10 transition-all group">
            <Clock className="text-yellow-400 mb-4 group-hover:scale-110 transition-transform" />
            <div className="text-4xl font-black">{token ? tasks.filter(t => t.status === 'Completed').length : '0'}</div>
            <div className="text-gray-500 text-xs font-bold uppercase tracking-widest mt-1">Completed Ops</div>
          </div>
        </div>

        <div className="flex justify-between items-center mb-10">
          <h2 className="text-3xl font-black italic">MISSION CONTROL</h2>
          {token && role === 'admin' && (
            <button 
              onClick={() => setIsTaskModalOpen(true)} 
              className="flex items-center gap-2 bg-indigo-600 px-8 py-4 rounded-2xl font-black hover:scale-105 transition-all shadow-xl shadow-indigo-500/20 active:scale-95"
            >
              <Plus size={20} /> NEW DEPLOYMENT
            </button>
          )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {token ? (
            tasks.length > 0 ? (
              tasks.map(t => <TaskCard key={t._id} task={t} refreshTasks={fetchTasks} />)
            ) : (
              <div className="col-span-full py-20 text-center text-gray-500 bg-white/5 border border-dashed border-white/10 rounded-3xl">
                No active missions assigned to your profile.
              </div>
            )
          ) : (
            <div className="col-span-full py-20 text-center text-gray-400 bg-indigo-600/5 border border-dashed border-indigo-500/20 rounded-3xl">
              <p className="text-lg font-bold mb-2">Access Restricted</p>
              <p className="text-sm">Please Login or Join the team to access the Mission Control board.</p>
            </div>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
};

export default Dashboard;
